#include <bits/stdc++.h>
#pragma GCC optimize("O2")
using namespace std;
#define int long long int

int fun(vector<int> &arr)
{
    int n = arr.size();
    unordered_map<int, int> mpp(0);

    int ans = 0;
    int sum = 0;
    mpp.insert({0, 1});
    for (auto num : arr)
    {
        sum += num;
        if (mpp.find(sum) != mpp.end())
        {
            ans += mpp[sum];
            mpp[sum] = mpp[sum] + 1;
        }
        else
            mpp[sum]++;
    }
    int total = (n * (n + 1)) / 2;
    return (total - ans);
}
signed main()
{


    int n, i ;

    cin >> n;

    vector<int> a(n, 0);

    for (i = 0; i < n; i++)
        cin >> a[i];

    cout << fun(a);
}

